"use client";

/* ════════════════════════════════════════════════════════════════════════
   BridgeLiquidate — write surface for clearing trapped capital.
   Ported from /Users/mac/Downloads/MAGELLAN UX/Bridge/Opertation/
   magellan-bridge-liquidate.html

   Pattern:
   - The trapped SKU summary (days of cover, on-hand, velocity, cost)
   - Method form (markdown / bundle / write-off + parameters)
   - Verdict card (CLEAR / HOLD / WAIT) with factor dots
   - "What this frees" consequence read (this clearance vs doing nothing)
   - Commit bar
   ════════════════════════════════════════════════════════════════════════ */

import { useMemo, useState } from "react";
import { useBridge } from "@/features/bridge/hooks/use-bridge";

type Method = "markdown" | "bundle" | "writeoff";

const METHOD_LABEL: Record<Method, string> = {
  markdown: "Markdown",
  bundle: "Bundle",
  writeoff: "Write off / donate",
};

// The trapped SKU in the demo
const SKU = {
  name: "Ceramic Vase — Tall White",
  meta: "Decor · 64 days since last sale · non-perishable",
  cover: 186,
  onHand: 312,
  velocity: 1.7,
  landed: 24,
  retail: 48,
  cm1: 50, // %
};

const fmtUSD = (v: number) => (v >= 1000 ? `$${(v / 1000).toFixed(1)}K` : `$${Math.round(v)}`);

export function BridgeLiquidate() {
  const { setPage } = useBridge();

  const [method, setMethod] = useState<Method>("markdown");
  const [discountInput, setDiscountInput] = useState("30%");
  const [unitsInput, setUnitsInput] = useState("312");
  const [applied, setApplied] = useState(false);

  // Parse discount %
  const discount = useMemo(() => {
    const n = parseFloat(discountInput.replace("%", "")) || 0;
    return Math.max(0, Math.min(95, n));
  }, [discountInput]);
  const units = useMemo(() => {
    const n = parseInt(unitsInput, 10);
    return Math.max(0, Math.min(SKU.onHand, isNaN(n) ? 0 : n));
  }, [unitsInput]);

  const clearPrice = useMemo(() => {
    if (method === "writeoff") return 0;
    return Math.round(SKU.retail * (1 - discount / 100));
  }, [method, discount]);

  // CM1 after markdown
  const cm1After = useMemo(() => {
    if (method === "writeoff") return -100;
    if (clearPrice === 0) return -100;
    return Math.round(((clearPrice - SKU.landed) / clearPrice) * 100);
  }, [clearPrice, method]);

  // Revenue / margin given up
  const fullRevenue = SKU.retail * units;
  const clearRevenue = clearPrice * units;
  const marginGivenUp = fullRevenue - clearRevenue;
  const capitalFreed = clearRevenue; // proxy: cash back from stock at clearance
  const stillProfitable = cm1After > 0;

  // Time-to-move heuristic at clearance pace (assume 3× normal velocity at markdown)
  const clearVelocity = method === "writeoff" ? units : SKU.velocity * (1 + (discount / 100) * 6);
  const timeToMove =
    method === "writeoff"
      ? "immediate"
      : clearVelocity > 0
        ? `~${Math.max(1, Math.round(units / clearVelocity / 7))} weeks at clearance pace`
        : "—";

  // Verdict
  const verdict =
    method === "writeoff" && SKU.cm1 >= 30
      ? "hold"
      : !stillProfitable
        ? "wait"
        : "clear";

  const apply = () => {
    setApplied(true);
    setTimeout(() => {
      setApplied(false);
      setPage("home");
    }, 1800);
  };

  return (
    <div className="bridge-content">
      <div className="bridge-page-head">
        <div className="bridge-page-head-icon">
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round">
            <path d="M5 7 h14 l-1.5 12 a1 1 0 0 1 -1 1 h-9 a1 1 0 0 1 -1 -1 z" />
            <path d="M9 7 V5 a1 1 0 0 1 1 -1 h4 a1 1 0 0 1 1 1 v2" />
            <path d="M10 11 l4 5 M14 11 l-4 5" />
          </svg>
        </div>
        <div>
          <div className="bridge-page-head-title">Clear Stock</div>
          <div className="bridge-page-head-sub">
            This SKU is trapping cash. Magellan recommends how to clear it and shows what you free vs. what you give up.
          </div>
        </div>
      </div>

      {/* The trapped SKU */}
      <div className="bridge-rb-sku">
        <div className="bridge-rb-sku-main">
          <div className="bridge-rb-sku-name">{SKU.name}</div>
          <div className="bridge-rb-sku-meta">{SKU.meta}</div>
        </div>
        <div className="bridge-rb-sku-stats">
          <div className="bridge-rb-stat">
            <span className="bridge-rb-stat-v alert">{SKU.cover}</span>
            <span className="bridge-rb-stat-k">days of cover</span>
          </div>
          <div className="bridge-rb-stat">
            <span className="bridge-rb-stat-v">{SKU.onHand}</span>
            <span className="bridge-rb-stat-k">on hand</span>
          </div>
          <div className="bridge-rb-stat">
            <span className="bridge-rb-stat-v">~{SKU.velocity}</span>
            <span className="bridge-rb-stat-k">/day velocity</span>
          </div>
          <div className="bridge-rb-stat">
            <span className="bridge-rb-stat-v">${SKU.landed}</span>
            <span className="bridge-rb-stat-k">landed cost</span>
          </div>
        </div>
      </div>

      {/* The action */}
      <div className="bridge-ni-card">
        <div className="bridge-ni-card-head">
          <span className="bridge-ni-section">How to clear it</span>
          <span className="bridge-ni-source manual">✏ Magellan recommends — adjust freely</span>
        </div>
        <div className="bridge-ni-grid">
          <div className="bridge-ni-field bridge-ni-span">
            <span className="bridge-ni-label">Method</span>
            <div className="bridge-ni-seg">
              {(["markdown", "bundle", "writeoff"] as Method[]).map((m) => (
                <button
                  key={m}
                  className={method === m ? "on" : ""}
                  onClick={() => setMethod(m)}
                  type="button"
                >
                  {METHOD_LABEL[m]}
                </button>
              ))}
            </div>
          </div>

          {method !== "writeoff" && (
            <>
              <div className="bridge-ni-field">
                <span className="bridge-ni-label">{method === "markdown" ? "Markdown" : "Bundle discount"}</span>
                <input
                  className="bridge-ni-input"
                  type="text"
                  value={discountInput}
                  onChange={(e) => setDiscountInput(e.target.value)}
                />
              </div>
              <div className="bridge-ni-field">
                <span className="bridge-ni-label">Clears at</span>
                <div className="bridge-ni-readout">
                  ${SKU.retail} → ${clearPrice}
                </div>
              </div>
            </>
          )}

          <div className="bridge-ni-field">
            <span className="bridge-ni-label">Units to clear</span>
            <input
              className="bridge-ni-input"
              type="text"
              value={unitsInput}
              onChange={(e) => setUnitsInput(e.target.value)}
            />
          </div>
          <div className="bridge-ni-field">
            <span className="bridge-ni-label">Time to move</span>
            <div className="bridge-ni-readout">{timeToMove}</div>
          </div>
        </div>
      </div>

      {/* Verdict */}
      <div className={`bridge-rb-verdict ${verdict}`}>
        <div className="bridge-rb-verdict-mark">
          {verdict === "clear" ? "CLEAR" : verdict === "hold" ? "HOLD" : "WAIT"}
        </div>
        <div className="bridge-rb-verdict-body">
          <div className="bridge-rb-verdict-line">
            {verdict === "clear"
              ? "Worth clearing — this capital has been frozen for months in a slow non-perishable. A markdown frees it with margin to spare."
              : verdict === "hold"
                ? "Hold — writing this off forfeits margin you could recover at a discount. Try a markdown or bundle first."
                : "Wait — at this discount the margin disappears. Reduce the discount or move fewer units."}
          </div>
          <div className="bridge-rb-verdict-factors">
            <div className="bridge-rb-factor">
              <span className="bridge-rb-factor-dot bad" />
              <span className="bridge-rb-factor-k">Capital trapped</span>
              <span className="bridge-rb-factor-v">
                {fmtUSD(SKU.landed * SKU.onHand)} sitting {SKU.cover} days
              </span>
            </div>
            <div className="bridge-rb-factor">
              <span className="bridge-rb-factor-dot bad" />
              <span className="bridge-rb-factor-k">Moving too slow</span>
              <span className="bridge-rb-factor-v">{SKU.velocity}/day — won&rsquo;t clear on its own</span>
            </div>
            <div className="bridge-rb-factor">
              <span className={`bridge-rb-factor-dot ${stillProfitable ? "ok" : "bad"}`} />
              <span className="bridge-rb-factor-k">Margin to give</span>
              <span className="bridge-rb-factor-v">
                {SKU.cm1}% CM1 — {stillProfitable ? "room to discount and still profit" : "thin — heavy markdown eats it"}
              </span>
            </div>
            <div className="bridge-rb-factor">
              <span className="bridge-rb-factor-dot ok" />
              <span className="bridge-rb-factor-k">No spoilage clock</span>
              <span className="bridge-rb-factor-v">non-perishable — clear at your pace</span>
            </div>
          </div>
        </div>
      </div>

      {/* What this frees */}
      <div className="bridge-ni-outcome">
        <div className="bridge-ni-outcome-head">
          <span className="m-mark">M</span> What this frees
          <span className="bridge-ni-outcome-prov firm">Computed from your ledger</span>
        </div>

        <div className="bridge-ni-outcome-tier">
          <div className="bridge-ni-tier-label">This clearance</div>
          <div className="bridge-ni-outcome-grid">
            <div className="bridge-ni-out">
              <span className="k">Capital freed</span>
              <span className="v good">{fmtUSD(capitalFreed)}</span>
              <span className="kk">cash back from stock</span>
            </div>
            <div className="bridge-ni-out">
              <span className="k">Margin given up</span>
              <span className="v">{fmtUSD(marginGivenUp)}</span>
              <span className="kk">vs. full price</span>
            </div>
            <div className="bridge-ni-out">
              <span className="k">Still profitable?</span>
              <span className={`v${stillProfitable ? " good" : " alert"}`}>
                {stillProfitable ? `Yes · ${cm1After}% CM1` : `No · ${cm1After}% CM1`}
              </span>
              <span className="kk">even after markdown</span>
            </div>
            <div className="bridge-ni-out">
              <span className="k">Storage freed</span>
              <span className="v">{units} units</span>
              <span className="kk">shelf space back</span>
            </div>
          </div>
        </div>

        <div className="bridge-ni-outcome-tier">
          <div className="bridge-ni-tier-label">Versus doing nothing</div>
          <div className="bridge-ni-outcome-grid">
            <div className="bridge-ni-out">
              <span className="k">If held at full price</span>
              <span className="v">~6 months</span>
              <span className="kk">to sell through</span>
            </div>
            <div className="bridge-ni-out">
              <span className="k">Capital locked that whole time</span>
              <span className="v alert">{fmtUSD(SKU.landed * SKU.onHand)}</span>
              <span className="kk">earning nothing</span>
            </div>
            <div className="bridge-ni-out">
              <span className="k">That cash, redeployed</span>
              <span className="v good">~{fmtUSD(SKU.landed * SKU.onHand * 3.6)} revenue</span>
              <span className="kk">in a fast SKU instead</span>
            </div>
            <div className="bridge-ni-out">
              <span className="k">Cost of waiting</span>
              <span className="v alert">high</span>
              <span className="kk">opportunity, not loss</span>
            </div>
          </div>
        </div>

        <div className="bridge-ni-outcome-note">
          Clearing isn&rsquo;t about the margin you lose — it&rsquo;s about the cash you <b>free and redeploy</b>. Magellan weighs trapped capital and velocity against the margin you&rsquo;d sacrifice, and recommends the lightest method that actually moves it. Write-off is only recommended when the stock won&rsquo;t sell at any reasonable price.
        </div>
      </div>

      {/* Commit */}
      <div className="bridge-ni-commit">
        <div className="bridge-ni-commit-note">
          This drafts the clearance — the markdown <b>isn&rsquo;t applied</b> to the live store until you confirm. Reversible.
        </div>
        <div className="bridge-ni-commit-btns">
          <button className="bridge-ni-cancel" type="button" onClick={() => setPage("home")}>
            Hold off
          </button>
          <button
            className={`bridge-ni-create${applied ? " done" : ""}`}
            type="button"
            onClick={apply}
            disabled={applied}
          >
            {applied
              ? `Markdown drafted ✓`
              : method === "writeoff"
                ? `Write off ${units} units →`
                : `Apply ${method === "bundle" ? "bundle" : "markdown"} — free ${fmtUSD(capitalFreed)} →`}
          </button>
        </div>
      </div>
    </div>
  );
}
